var e=[{id:`L2_1`,type:`dialog`,speaker:`ANDRO_EXTRA_NULL_NULL`,text:{KOREA:`말도 안돼! 어떻게 여길 찾은 거지?`,JPN:`どういうことだ！　なぜここがバレたんだ？`,ENG:`This can't be! How did they find this place?`,TWN:`怎麼可能！你們是怎麼找到這裡的？`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ANDRO_EXTRA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`SOYEONG_POLICE_NULL_NULL`,text:{KOREA:`배송조회를 했더니 금방 나오던데요?`,JPN:`配達照会をしたらすぐに出ましたよ？`,ENG:`I ran some logistics analysis.`,TWN:`查了下物流情況馬上就找到了啊？`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOYEONG_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`SOYEONG_POLICE_NULL_NULL`,text:{KOREA:`가게도 아니면서 인터넷으로 빵봉투를 그렇게 많이 주문하는 곳이 당신들 말고 달리 있겠어요?`,JPN:`お店でもないのに、ネットで紙袋を大量に注文する所といえば、
あなたたちしかいないでしょう？`,ENG:`It turns out there aren't many non-bakery venues that order so many paper bread bags.`,TWN:`又不是商店，卻上網定了這麼多麵包紙袋，會做這種事的也就只有你們了吧？`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOYEONG_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`SOYEONG_POLICE_NULL_NULL`,text:{KOREA:`경찰의 수사력을 얕보지 말라고요.`,JPN:`警察の捜査力を見くびらないでください。`,ENG:`You shouldn't have underestimated the investigative power of the police.`,TWN:`可別小看警察的調查能力。`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOYEONG_POLICE_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`YUMI_POLICE_NULL_NULL`,text:{KOREA:`아니 그건...... 아무리 봐도 우리 수사력이 뛰어난 게 아니라 이 녀석들이 멍청한 것 같은데......`,JPN:`いやそれは……どう考えても警察の捜査力じゃなくて、こいつらがアホなだけだと思うけど……`,ENG:`Erm... I'd say it's their stupidity rather than our investigative power that led us here...`,TWN:`不，這個……不管怎麼看，都不是我們調查能力強，而是這些傢伙太笨了吧……`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`ANDRO_EXTRA_NULL_NULL`,text:{KOREA:`이런 바보 같은 놈!`,JPN:`このバカども！`,ENG:`You fool!`,TWN:`你們這群蠢材！`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`ANDRO_EXTRA_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`ZELOT_MAGELLAN_NULL_BAG`,face:`UNIT_IDLE`}}}},{id:`L10_1`,type:`dialog`,speaker:`ANDRO_EXTRA_NULL_NULL`,text:{KOREA:`그런 건 구매할 때 주소지를 바꾸라고 몇 번이나 말했잖아!`,JPN:`買う度に住所を変えろと何度も言っただろう！`,ENG:`How many times did I tell you to change addresses when you order the bags?`,TWN:`買這種東西時要換個收貨地址，我不是說了好幾次了嘛！`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`ANDRO_EXTRA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`ZELOT_MAGELLAN_NULL_BAG`,face:`UNIT_IDLE`}}}},{id:`L11_1`,type:`dialog`,speaker:`ZELOT_MAGELLAN_NULL_BAG`,text:{KOREA:`죄, 죄송합니다! 인터넷 쇼핑몰 메뉴가 너무 복잡해서......`,JPN:`も、申し訳ありません！　ネットショップのメニューが複雑なもので……`,ENG:`I-I'm sorry, bishop! There were a lot of things on the screen and online shopping is really confusing...`,TWN:`非、非常抱歉！網購頁面太複雜了，所以……`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`ANDRO_EXTRA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`ZELOT_MAGELLAN_NULL_BAG`,face:`UNIT_IDLE`}}}},{id:`L12_1`,type:`dialog`,speaker:`ANDRO_EXTRA_NULL_NULL`,text:{KOREA:`일단 계획은 취소다! 우선 여길 뜨자고!`,JPN:`いったん計画は取消しだ！　まずここから出よう！`,ENG:`We abandon the plan for now! Let's get out of here!`,TWN:`總之計畫暫時取消！我們得先離開這裡！`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`ANDRO_EXTRA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`ZELOT_MAGELLAN_NULL_BAG`,face:`UNIT_IDLE`}}}},{id:`L14_1`,type:`dialog`,speaker:`SOYEONG_POLICE_NULL_NULL`,text:{KOREA:`경정님!`,JPN:`警視様！！`,ENG:`Major!`,TWN:`警正大人！`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOYEONG_POLICE_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`YUMI_POLICE_NULL_NULL`,text:{KOREA:`걱정마! 무능...... 아니 강소영 경위! 나한테 맡겨!`,JPN:`心配しないで！　無能……いや、マエカワ警部補！
私に任せなさい！`,ENG:`All right, incompe— I mean, Lieutenant! I've got this covered!`,TWN:`不用擔心！無能力……不，姜素英警衛！交給我吧！`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};